    cmd = f'. "{repo_root}/agentic-development/lib/cost-tracker.sh"; export_session_json "{sid}" "{tmp.name}"'
    subprocess.check_call(["bash", "-lc", cmd], cwd=repo_root)
    with open(tmp.name, "r") as f:
        data = json.load(f)
    os.unlink(tmp.name)
    return data

